import React, { useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import resume from '../resume/resume';
import './Home.css';

function FloatingOrb({ style }) {
  return <div className="orb" style={style} />;
}

export default function Home() {
  const heroRef = useRef(null);

  useEffect(() => {
    const el = heroRef.current;
    if (!el) return;
    const onMove = (e) => {
      const { clientX: x, clientY: y } = e;
      const cx = window.innerWidth / 2;
      const cy = window.innerHeight / 2;
      const rotX = ((y - cy) / cy) * -8;
      const rotY = ((x - cx) / cx) *  8;
      el.style.transform = `perspective(1200px) rotateX(${rotX}deg) rotateY(${rotY}deg)`;
    };
    const onLeave = () => { el.style.transform = 'perspective(1200px) rotateX(0) rotateY(0)'; };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseleave', onLeave);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseleave', onLeave);
    };
  }, []);

  return (
    <div className="home page-enter">
      {/* Background orbs */}
      <FloatingOrb style={{ width: 500, height: 500, top: '-10%', left: '-5%', background: 'radial-gradient(circle, rgba(230,57,70,0.12) 0%, transparent 70%)', animationDelay: '0s' }} />
      <FloatingOrb style={{ width: 400, height: 400, bottom: '10%', right: '-5%', background: 'radial-gradient(circle, rgba(76,201,240,0.1) 0%, transparent 70%)', animationDelay: '-3s' }} />
      <FloatingOrb style={{ width: 300, height: 300, top: '40%', left: '50%', background: 'radial-gradient(circle, rgba(244,162,97,0.08) 0%, transparent 70%)', animationDelay: '-6s' }} />

      <div className="hero-grid">
        {/* Left — Text */}
        <div className="hero-text" ref={heroRef}>
          <p className="hero-tag">
            <span className="tag-dot" />
            Available for opportunities
          </p>

          <h1 className="hero-name">
            <span className="name-first">ROHIT</span>
            <span className="name-last">SINGH<br/>GOURIA</span>
          </h1>

          <p className="hero-role">
            Frontend Developer <span className="role-divider">/</span> CS Undergrad
            <br />
            <span className="hero-sub">Intern @ ProDesk IT · ACEIT Jaipur · GPA 9.45</span>
          </p>

          <div className="hero-actions">
            <Link to="/projects" className="btn-primary">View Projects →</Link>
            <Link to="/contact" className="btn-outline">Get In Touch</Link>
          </div>

          <div className="hero-stats">
            <div className="stat">
              <span className="stat-num">9.45</span>
              <span className="stat-label">GPA</span>
            </div>
            <div className="stat-divider" />
            <div className="stat">
              <span className="stat-num">4+</span>
              <span className="stat-label">Projects</span>
            </div>
            <div className="stat-divider" />
            <div className="stat">
              <span className="stat-num">5+</span>
              <span className="stat-label">Certs</span>
            </div>
          </div>
        </div>

        {/* Right — 3D Card */}
        <div className="hero-card-wrap">
          <div className="hero-card">
            <div className="card-glow" />
            <div className="card-header">
              {/* ── PROFILE IMAGE ──────────────────────────────────────
                  To add your photo later, replace the placeholder below:
                  Change:  src=""
                  To:      src="YOUR_IMAGE_URL_HERE"
                  Example: src="https://i.imgur.com/yourphoto.jpg"
                  ─────────────────────────────────────────────────── */}
              <div className="card-photo-wrap">
                <img
                  src=""
                  alt="Rohit Singh Gouria"
                  className="card-photo"
                  onError={e => { e.target.style.display = 'none'; e.target.nextSibling.style.display = 'flex'; }}
                />
                <div className="card-photo-placeholder">
                  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                    <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
                    <circle cx="12" cy="7" r="4"/>
                  </svg>
                  <span>Add Photo</span>
                </div>
              </div>
              <div>
                <p className="card-name">Rohit Singh Gouria</p>
                <p className="card-title">Frontend Developer</p>
              </div>
            </div>
            <div className="card-divider" />
            <div className="card-stack">
              {['React', 'JavaScript', 'C++', 'SQL', 'Git'].map(t => (
                <span key={t} className="card-tag">{t}</span>
              ))}
            </div>
            <div className="card-project">
              <p className="cp-label">Latest Project</p>
              <a href="https://rsgshopzone.netlify.app/" target="_blank" rel="noreferrer" className="cp-link">
                ShopZone — E-Commerce SPA ↗
              </a>
            </div>
            <div className="card-footer">
              <a href="https://github.com/Rohit551800" target="_blank" rel="noreferrer" className="cf-item">⌨ GitHub</a>
              <a href="mailto:rohitsingh139915@gmail.com" className="cf-item">✉ Email</a>
            </div>
          </div>
        </div>
      </div>

      {/* Scroll hint */}
      <div className="scroll-hint">
        <span>Scroll</span>
        <div className="scroll-line" />
      </div>
    </div>
  );
}
